37	export function looksLikeMattermostTargetId(raw: string, normalized?: string): boolean {
38	  const trimmed = raw.trim();
39	  if (!trimmed) {
40	    return false;
41	  }
42	  if (/^(user|channel|group|mattermost):/i.test(trimmed)) {
43	    return true;
44	  }
45	  if (trimmed.startsWith("@")) {
46	    return true;
47	  }
48	  // Mattermost IDs: 26-char alnum, or DM channels like "abc123__xyz789" (53 chars)
49	  return /^[a-z0-9]{26}$/i.test(trimmed) || /^[a-z0-9]{26}__[a-z0-9]{26}$/i.test(trimmed);
