### 2k. `extensions/pulseboard/src/normalize.ts`

**Purpose:** Target normalization and allowlist helpers for PulseBoard's target format.

**Key exports:** `normalizePulseBoardMessagingTarget`, `looksLikePulseBoardTargetId`, `isBoardTarget`, `normalizePulseBoardAllowEntry`, `normalizePulseBoardAllowlist`, `formatPulseBoardSenderId`.

**Implementation details:**

```typescript
// A board target starts with '$'
export function isBoardTarget(target: string): boolean {
  return target.startsWith("$");
}

// Valid PulseBoard target: $board-name (group) or plain username (DM)
// Rules:
//   - strip "pulseboard:" prefix if present
//   - strip "board:" prefix and ensure "$" prefix if group
//   - strip "user:" prefix for DMs
//   - remaining must be non-empty, no whitespace, no control chars
export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) return undefined;
  let target = trimmed;
  const lower = target.toLowerCase();
  if (lower.startsWith("pulseboard:")) target = target.slice("pulseboard:".length).trim();
  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    if (!target.startsWith("$")) target = `$${target}`;
  }
  if (target.toLowerCase().startsWith("user:")) target = target.slice("user:".length).trim();
  if (!target || !looksLikePulseBoardTargetId(target)) return undefined;
  return target;
}

// A valid target id: "$" + non-empty slug, or a plain non-empty username (no whitespace)
const PULSEBOARD_TARGET_PATTERN = /^[^\s]+$/u;
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) return false;
  return PULSEBOARD_TARGET_PATTERN.test(trimmed);
}

// Normalize an allowFrom entry: lowercase, strip "pulseboard:" / "user:" prefixes
export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) return "";
  if (value.startsWith("pulseboard:")) value = value.slice("pulseboard:".length);
  if (value.startsWith("user:")) value = value.slice("user:".length);
  return value.trim();
}

export function normalizePulseBoardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? []).map((e) => normalizePulseBoardAllowEntry(String(e))).filter(Boolean);
}

// Format a sender id for display/allowlist matching
export function formatPulseBoardSenderId(message: PulseBoardInboundMessage): string {
  return message.senderUsername.trim();
}

// Build allowlist candidates for a message (just the username, lowercased)
export function buildPulseBoardAllowlistCandidates(message: PulseBoardInboundMessage): string[] {
  const username = message.senderUsername.trim().toLowerCase();
  return username ? [username] : [];
}

// Check if a sender is on the allowlist
export function resolvePulseBoardAllowlistMatch(params: {
  allowFrom: string[];
  message: PulseBoardInboundMessage;
}): { allowed: boolean; source?: string } {
  const set = new Set(params.allowFrom.map((e) => e.trim().toLowerCase()).filter(Boolean));
  if (set.has("*")) return { allowed: true, source: "wildcard" };
  const username = params.message.senderUsername.trim().toLowerCase();
  if (username && set.has(username)) return { allowed: true, source: username };
  return { allowed: false };
}
```

