### 2p. `extensions/pulseboard/src/probe.ts`

**Purpose:** HTTP connectivity check.

**Key export:** `probePulseBoard(cfg, opts?): Promise<PulseBoardProbe>`

**Imports:** `./accounts.js`; `./types.js`.

**Implementation:**
```typescript
export async function probePulseBoard(
  cfg: CoreConfig,
  opts?: { accountId?: string; timeoutMs?: number }
): Promise<PulseBoardProbe> {
  const account = resolvePulseBoardAccount({ cfg, accountId: opts?.accountId });
  const base: PulseBoardProbe = { ok: false, host: account.host, username: account.username };
  if (!account.configured) return { ...base, error: "missing host, token, or username" };

  const started = Date.now();
  try {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), opts?.timeoutMs ?? 8000);
    const res = await fetch(`${account.host}/api/status`, {
      method: "GET",
      headers: { Authorization: `Bearer ${account.token}` },
      signal: controller.signal,
    });
    clearTimeout(timeoutId);
    if (!res.ok) return { ...base, error: `HTTP ${res.status}` };
    return { ...base, ok: true, latencyMs: Date.now() - started };
  } catch (err) {
    return { ...base, error: err instanceof Error ? err.message : String(err) };
  }
}
```

