### 15. `src/channel.ts`

**Key export:** `pulseBoardPlugin`

**Imports:** All local `src/` modules + public SDK paths listed earlier.

```typescript
export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount, PulseBoardProbe> =
  createChatChannelPlugin({
    base: {
      id: "pulseboard",
      meta: { ...getChatChannelMeta("pulseboard"), quickstartAllowFrom: true },
      setup: pulseBoardSetupAdapter,
      setupWizard: pulseBoardSetupWizard,
      capabilities: { chatTypes: ["direct", "group"], media: true, blockStreaming: true },
      reload: { configPrefixes: ["channels.pulseboard"] },
      configSchema: PulseBoardChannelConfigSchema,
      config: {
        ...pulseBoardConfigAdapter,  // createScopedChannelConfigAdapter(...)
        isConfigured: (account) => account.configured,
        describeAccount: (account) => describeAccountSnapshot({ account, configured: account.configured,
          extra: { host: account.host, username: account.username, tokenSource: account.tokenSource } }),
      },
      groups: {
        resolveRequireMention: ({ cfg, accountId, groupId }) => { /* look up board config, default true */ },
        resolveToolPolicy: ({ cfg, accountId, groupId }) => { /* look up board tools config */ },
      },
      messaging: {
        normalizeTarget: normalizePulseBoardMessagingTarget,
        targetResolver: { looksLikeId: looksLikePulseBoardTargetId, hint: "<$board|username>" },
      },
      resolver: { resolveTargets: async ({ inputs, kind }) => { /* ensure $ for group, reject boards for direct */ } },
      directory: createChannelDirectoryAdapter({
        listPeers: async (params) => listPulseBoardDirectoryPeersFromConfig(params),
        listGroups: async (params) => listPulseBoardDirectoryGroupsFromConfig(params),
      }),
      status: createComputedAccountStatusAdapter<ResolvedPulseBoardAccount, PulseBoardProbe>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        buildChannelSummary: ({ account, snapshot }) => ({
          ...buildBaseChannelStatusSummary(snapshot),
          host: account.host, username: account.username, probe: snapshot.probe,
        }),
        probeAccount: async ({ cfg, account, timeoutMs }) =>
          probePulseBoard(cfg as CoreConfig, { accountId: account.accountId, timeoutMs }),
        resolveAccountSnapshot: ({ account }) => ({
          accountId: account.accountId, name: account.name, enabled: account.enabled,
          configured: account.configured,
          extra: { host: account.host, username: account.username, tokenSource: account.tokenSource },
        }),
      }),
      gateway: {
        startAccount: async (ctx) => {
          if (!ctx.account.configured) throw new Error("PulseBoard not configured...");
          const statusSink = createAccountStatusSink({ accountId: ctx.accountId, setStatus: ctx.setStatus });
          await runStoppablePassiveMonitor({
            abortSignal: ctx.abortSignal,
            start: async () => await monitorPulseBoardProvider({
              accountId: ctx.account.accountId, config: ctx.cfg as CoreConfig,
              runtime: ctx.runtime, abortSignal: ctx.abortSignal, statusSink,
            }),
          });
        },
      },
    },
    pairing: {
      text: {
        idLabel: "pulseBoardUser",
        message: PAIRING_APPROVED_MESSAGE,
        normalizeAllowEntry: normalizePulseBoardAllowEntry,
        notify: async ({ id, message }) => { await sendMessagePulseBoard(id, message); },
      },
    },
    security: {
      resolveDmPolicy: createScopedDmSecurityResolver({
        channelKey: "pulseboard",
        resolvePolicy: (account) => account.config.dmPolicy,
        resolveAllowFrom: (account) => account.config.allowFrom,
        policyPathSuffix: "dmPolicy",
        normalizeEntry: normalizePulseBoardAllowEntry,
      }),
      collectWarnings: composeAccountWarningCollectors<ResolvedPulseBoardAccount>(
        createAllowlistProviderOpenWarningCollector({
          providerConfigPresent: (cfg) => cfg.channels?.pulseboard !== undefined,
          resolveGroupPolicy: (account) => account.config.groupPolicy,
          buildOpenWarning: {
            surface: "PulseBoard boards",
            openBehavior: "allows all boards and senders (mention-gated)",
            remediation: 'Prefer channels.pulseboard.groupPolicy="allowlist" with channels.pulseboard.groups',
          },
        }),
      ),
    },
    outbound: {
      base: {
        deliveryMode: "direct",
        chunker: chunkTextForOutbound,
        chunkerMode: "markdown",
        textChunkLimit: 4000,
      },
      attachedResults: {
        channel: "pulseboard",
        sendText: async ({ cfg, to, text, accountId, replyToId }) =>
          await sendMessagePulseBoard(to, text, { cfg: cfg as CoreConfig, accountId: accountId ?? undefined, replyTo: replyToId ?? undefined }),
        sendMedia: async ({ cfg, to, text, mediaUrl, accountId, replyToId }) =>
          await sendMessagePulseBoard(to, mediaUrl ? `${text}\n\nAttachment: ${mediaUrl}` : text,
            { cfg: cfg as CoreConfig, accountId: accountId ?? undefined, replyTo: replyToId ?? undefined }),
      },
    },
  });
```

**Directory helpers** (local to `channel.ts`):
- `listPulseBoardDirectoryPeersFromConfig` — `createResolvedDirectoryEntriesLister({ kind: "user", ... })` using `allowFrom`/`groupAllowFrom`/per-board `allowFrom`; filter out board-prefixed entries and wildcards
- `listPulseBoardDirectoryGroupsFromConfig` — `createResolvedDirectoryEntriesLister({ kind: "group", ... })` using `config.boards` + `Object.keys(config.groups ?? {})`; keep only `isBoardTarget` entries

**Config adapter** (local to `channel.ts`):
- `pulseBoardConfigAdapter = createScopedChannelConfigAdapter<ResolvedPulseBoardAccount, ...>({ sectionKey: "pulseboard", listAccountIds: listPulseBoardAccountIds, resolveAccount: adaptScopedAccountAccessor(resolvePulseBoardAccount), defaultAccountId: resolveDefaultPulseBoardAccountId, clearBaseFields: ["host", "token", "username", "boards"], resolveAllowFrom: (a) => a.config.allowFrom, formatAllowFrom: (allowFrom) => formatNormalizedAllowFromEntries({ allowFrom, normalizeEntry: normalizePulseBoardAllowEntry }), resolveDefaultTo: (a) => a.config.dms?.[DEFAULT_ACCOUNT_ID] ? undefined : undefined })`

