        chunkerMode: "markdown",
        textChunkLimit: 4000,
      },
      attachedResults: {
        channel: "pulseboard",
        sendText: async ({ cfg, to, text, accountId, replyToId }) =>
          await sendMessagePulseBoard(to, text, { cfg: cfg as CoreConfig, accountId: accountId ?? undefined, replyTo: replyToId ?? undefined }),
        sendMedia: async ({ cfg, to, text, mediaUrl, accountId, replyToId }) =>
          await sendMessagePulseBoard(to, mediaUrl ? `${text}\n\nAttachment: ${mediaUrl}` : text,
            { cfg: cfg as CoreConfig, accountId: accountId ?? undefined, replyTo: replyToId ?? undefined }),
      },
    },
  });
