import type { PulseBoardInboundMessage } from "./types.js";

/** Returns true when a normalized target is a board (group) rather than a DM. */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("$");
}

const PULSEBOARD_TARGET_PATTERN = /^[^\s]+$/u;

/** Returns true when a raw string looks like a valid PulseBoard target id. */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  return PULSEBOARD_TARGET_PATTERN.test(trimmed);
}

/**
 * Normalize a raw target string for PulseBoard.
 *
 * Rules:
 * - Strip leading/trailing whitespace.
 * - Strip "pulseboard:" prefix if present.
 * - Strip "board:" prefix and ensure "$" prefix → board target.
 * - Strip "user:" prefix → DM target.
 * - Remaining must be non-empty, no whitespace.
 *
 * Returns undefined for invalid/empty targets.
 */
export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
  let target = raw.trim();
  if (!target) {
    return undefined;
  }

  // Strip top-level provider prefix.
  const lower = target.toLowerCase();
  if (lower.startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }

  // Coerce board: prefix into $ notation.
  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    if (!target.startsWith("$")) {
      target = `$${target}`;
    }
  }

  // Strip user: prefix for DMs.
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  }

  if (!target || !looksLikePulseBoardTargetId(target)) {
    return undefined;
  }

  return target;
}

/**
 * Normalize a raw allowFrom entry for PulseBoard DM policy.
 * Lowercases and strips "pulseboard:" / "user:" prefixes.
 */
export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length).trim();
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length).trim();
  }
  return value.trim();
}

/** Normalize an array of allowFrom entries, filtering out empty results. */
export function normalizePulseBoardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? [])
    .map((e) => normalizePulseBoardAllowEntry(String(e)))
    .filter(Boolean);
}

/**
 * Check whether the sender of a message is on the effective allowFrom list.
 * Supports "*" wildcard.
 */
export function resolvePulseBoardAllowlistMatch(params: {
  allowFrom: string[];
  message: PulseBoardInboundMessage;
}): { allowed: boolean } {
  const set = new Set(
    params.allowFrom.map((e) => e.trim().toLowerCase()).filter(Boolean),
  );
  if (set.has("*")) {
    return { allowed: true };
  }
  const username = params.message.senderUsername.trim().toLowerCase();
  if (username && set.has(username)) {
    return { allowed: true };
  }
  return { allowed: false };
}

/** Format a sender display label for logging. */
export function formatPulseBoardSenderId(message: PulseBoardInboundMessage): string {
  return message.senderUsername.trim();
}

/**
 * Normalize a board group entry for group config keys.
 * Ensures "$" prefix for board names; returns null for invalid entries.
 */
export function normalizeBoardEntry(raw: string): string | null {
  const trimmed = raw.trim();
  if (!trimmed) {
    return null;
  }
  if (trimmed === "*") {
    return "*";
  }
  if (isBoardTarget(trimmed)) {
    return trimmed;
  }
  // Treat bare names as board names.
  return `$${trimmed.replace(/^\$+/, "")}`;
}

