import { resolveMarkdownTableMode } from "openclaw/plugin-sdk/config-runtime";
import { convertMarkdownTables } from "openclaw/plugin-sdk/text-runtime";
import { resolvePulseBoardAccount } from "./accounts.js";
import { normalizePulseBoardMessagingTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

type SendPulseBoardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  replyTo?: string;
};

export type SendPulseBoardResult = {
  messageId: string;
  target: string;
};

function recordOutboundActivity(accountId: string): void {
  try {
    getPulseBoardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (err) {
    // Tolerate "not initialized" errors (e.g. during tests or transient sends).
    if (!(err instanceof Error) || err.message !== "PulseBoard runtime not initialized") {
      throw err;
    }
  }
}

/**
 * Send a text message to a PulseBoard target via the HTTP API.
 *
 * The target can be a board ($board-name) for group messages or a plain
 * username for direct messages. Throws on invalid target or unconfigured account.
 */
export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need host, token, and username in channels.pulseboard).`,
    );
  }

  const target = normalizePulseBoardMessagingTarget(to);
  if (!target) {
    throw new Error(`Invalid PulseBoard target: ${to}`);
  }

  const tableMode = resolveMarkdownTableMode({ cfg, channel: "pulseboard", accountId: account.accountId });
  const prepared = convertMarkdownTables(text.trim(), tableMode);
  const payload = opts.replyTo ? `${prepared}\n\n[reply:${opts.replyTo}]` : prepared;

  if (!payload.trim()) {
    throw new Error("Message must be non-empty for PulseBoard sends");
  }

  const res = await fetch(`${account.host}/api/send`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${account.token}`,
    },
    body: JSON.stringify({ to: target, text: payload }),
  });

  if (!res.ok) {
    throw new Error(`PulseBoard send failed: HTTP ${res.status}`);
  }

  recordOutboundActivity(account.accountId);

  return {
    messageId: crypto.randomUUID(),
    target,
  };
}

