import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import { resolvePulseBoardAccount } from "./accounts.js";
import { handlePulseBoardInbound } from "./inbound.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig, PulseBoardInboundMessage, RuntimeEnv } from "./types.js";

export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  onMessage?: (message: PulseBoardInboundMessage) => void | Promise<void>;
};

type PulseBoardWsEvent = {
  messageId: string;
  target: string;
  senderUsername: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};

function isPulseBoardWsEvent(obj: unknown): obj is PulseBoardWsEvent {
  if (typeof obj !== "object" || obj === null) {
    return false;
  }
  const evt = obj as Record<string, unknown>;
  return (
    typeof evt.messageId === "string" &&
    typeof evt.target === "string" &&
    typeof evt.senderUsername === "string" &&
    typeof evt.text === "string" &&
    typeof evt.timestamp === "number" &&
    typeof evt.isGroup === "boolean"
  );
}

/**
 * Connect to the PulseBoard server and process inbound messages.
 *
 * Uses a WebSocket connection for real-time delivery. Each incoming JSON event
 * is validated and forwarded to handlePulseBoardInbound (unless opts.onMessage
 * is provided, in which case the caller handles dispatch).
 *
 * Returns a stop() function to terminate the connection.
 */
export async function monitorPulseBoardProvider(
  opts: PulseBoardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseBoardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
    opts.runtime,
    core.logging.getChildLogger(),
  );

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need host, token, and username in channels.pulseboard).`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  let ws: WebSocket | null = null;
  let stopped = false;

  const wsUrl = `${account.host.replace(/^https?:\/\//, (m) => (m === "https://" ? "wss://" : "ws://"))}/ws?token=${encodeURIComponent(account.token)}`;

  ws = new WebSocket(wsUrl);

  ws.addEventListener("open", () => {
    logger.info(
      `[${account.accountId}] connected to PulseBoard at ${account.host} as ${account.username}`,
    );

    // Subscribe to configured boards.
    const boards = account.config.boards ?? [];
    if (boards.length > 0 && ws?.readyState === WebSocket.OPEN) {
      ws.send(JSON.stringify({ type: "subscribe", boards }));
    }
  });

  ws.addEventListener("message", async (event) => {
    if (stopped) {
      return;
    }

    let parsed: unknown;
    try {
      parsed = JSON.parse(String(event.data));
    } catch {
      runtime.log?.(`pulseboard: received non-JSON message; skipping`);
      return;
    }

    if (!isPulseBoardWsEvent(parsed)) {
      return;
    }

    // Skip self-messages.
    if (parsed.senderUsername === account.username) {
      return;
    }

    const message: PulseBoardInboundMessage = {
      messageId: parsed.messageId,
      target: parsed.target,
      senderUsername: parsed.senderUsername,
      text: parsed.text,
      timestamp: parsed.timestamp,
      isGroup: parsed.isGroup,
    };

    core.channel.activity.record({
      channel: "pulseboard",
      accountId: account.accountId,
      direction: "inbound",
      at: message.timestamp,
    });

    if (opts.onMessage) {
      await opts.onMessage(message);
      return;
    }

    await handlePulseBoardInbound({
      message,
      account,
      config: cfg,
      runtime,
      sendReply: async (target, text) => {
        if (ws?.readyState === WebSocket.OPEN) {
          // Deliver via the HTTP send API for reliability.
          await import("./send.js").then(({ sendMessagePulseBoard }) =>
            sendMessagePulseBoard(target, text, { cfg, accountId: account.accountId }),
          );
          opts.statusSink?.({ lastOutboundAt: Date.now() });
          core.channel.activity.record({
            channel: "pulseboard",
            accountId: account.accountId,
            direction: "outbound",
          });
        }
      },
      statusSink: opts.statusSink,
    });
  });

  ws.addEventListener("error", (event) => {
    logger.error(`[${account.accountId}] PulseBoard WebSocket error: ${String(event)}`);
  });

  ws.addEventListener("close", () => {
    if (!stopped) {
      logger.info(`[${account.accountId}] PulseBoard WebSocket closed`);
    }
  });

  // Honour the abort signal.
  opts.abortSignal?.addEventListener("abort", () => {
    stopped = true;
    ws?.close();
    ws = null;
  });

  return {
    stop: () => {
      stopped = true;
      ws?.close();
      ws = null;
    },
  };
}

