      .map((e) => normalizePulseBoardAllowEntry(e))
      .filter(Boolean);
    const merged = [...new Set([...existing.map(String), ...entries])];
    return {
      cfg: setPulseBoardAllowFrom(cfg as CoreConfig, merged),
      credentialValues: {},
    };
  },
};

