import { afterEach, beforeEach, describe, expect, it } from "vitest";
import {
  listEnabledPulseBoardAccounts,
  listPulseBoardAccountIds,
  resolvePulseBoardAccount,
} from "./accounts.js";
import type { CoreConfig } from "./types.js";

function makeConfig(pulseboard: Record<string, unknown> = {}): CoreConfig {
  return { channels: { pulseboard } } as CoreConfig;
}

describe("resolvePulseBoardAccount", () => {
  const originalEnv: Record<string, string | undefined> = {};
  const envKeys = [
    "PULSEBOARD_HOST",
    "PULSEBOARD_TOKEN",
    "PULSEBOARD_USERNAME",
    "PULSEBOARD_BOARDS",
  ];

  beforeEach(() => {
    for (const key of envKeys) {
      originalEnv[key] = process.env[key];
      delete process.env[key];
    }
  });

  afterEach(() => {
    for (const key of envKeys) {
      if (originalEnv[key] === undefined) {
        delete process.env[key];
      } else {
        process.env[key] = originalEnv[key];
      }
    }
  });

  it("returns configured=false when any required field is missing", () => {
    const cfg = makeConfig({ host: "https://pb.example.com", token: "tok" });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(false);
  });

  it("returns configured=true when host, token, and username are all present", () => {
    const cfg = makeConfig({
      host: "https://pb.example.com",
      token: "tok123",
      username: "mybot",
    });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(true);
    expect(account.host).toBe("https://pb.example.com");
    expect(account.username).toBe("mybot");
  });

  it("resolves host, token, username from env vars for default account", () => {
    process.env.PULSEBOARD_HOST = "https://env.example.com";
    process.env.PULSEBOARD_TOKEN = "envtoken";
    process.env.PULSEBOARD_USERNAME = "envbot";

    const account = resolvePulseBoardAccount({ cfg: makeConfig() });
    expect(account.configured).toBe(true);
    expect(account.host).toBe("https://env.example.com");
    expect(account.token).toBe("envtoken");
    expect(account.tokenSource).toBe("env");
    expect(account.username).toBe("envbot");
  });

  it("parses PULSEBOARD_BOARDS env var", () => {
    process.env.PULSEBOARD_HOST = "https://pb.example.com";
    process.env.PULSEBOARD_TOKEN = "tok";
    process.env.PULSEBOARD_USERNAME = "bot";
    process.env.PULSEBOARD_BOARDS = "$general,$ops";

    const account = resolvePulseBoardAccount({ cfg: makeConfig() });
    expect(account.config.boards).toEqual(["$general", "$ops"]);
  });

  it("parses PULSEBOARD_BOARDS with newline separator", () => {
    process.env.PULSEBOARD_HOST = "https://pb.example.com";
    process.env.PULSEBOARD_TOKEN = "tok";
    process.env.PULSEBOARD_USERNAME = "bot";
    process.env.PULSEBOARD_BOARDS = "$alpha\n$beta";

    const account = resolvePulseBoardAccount({ cfg: makeConfig() });
    expect(account.config.boards).toEqual(["$alpha", "$beta"]);
  });

  it("falls back to named account if default account is not configured", () => {
    const cfg = makeConfig({
      accounts: {
        work: {
          host: "https://work.example.com",
          token: "worktok",
          username: "workbot",
        },
      },
      defaultAccount: "work",
    });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(true);
    expect(account.accountId).toBe("work");
  });

  it("uses explicit accountId when provided", () => {
    const cfg = makeConfig({
      host: "https://pb.example.com",
      token: "tok",
      username: "bot",
      accounts: {
        secondary: {
          host: "https://sec.example.com",
          token: "sectok",
          username: "secbot",
        },
      },
    });
    const account = resolvePulseBoardAccount({ cfg, accountId: "secondary" });
    expect(account.accountId).toBe("secondary");
    expect(account.host).toBe("https://sec.example.com");
  });

  it("returns tokenSource=config when token comes from config", () => {
    const cfg = makeConfig({ host: "https://pb.example.com", token: "cfg-tok", username: "bot" });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.tokenSource).toBe("config");
  });

  it("returns tokenSource=none when no token is available", () => {
    const cfg = makeConfig({ host: "https://pb.example.com", username: "bot" });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.tokenSource).toBe("none");
  });
});

describe("listPulseBoardAccountIds", () => {
  it("returns default account id when no accounts block", () => {
    const cfg = makeConfig({ host: "https://pb.example.com" });
    const ids = listPulseBoardAccountIds(cfg);
    expect(ids.length).toBeGreaterThanOrEqual(1);
  });

  it("includes named accounts", () => {
    const cfg = makeConfig({
      accounts: { alpha: { host: "h" }, beta: { host: "h2" } },
    });
    const ids = listPulseBoardAccountIds(cfg);
    expect(ids).toContain("alpha");
    expect(ids).toContain("beta");
  });
});

describe("listEnabledPulseBoardAccounts", () => {
  it("excludes accounts with enabled=false", () => {
    const cfg = makeConfig({
      host: "https://pb.example.com",
      token: "tok",
      username: "bot",
      accounts: {
        disabled: { enabled: false, host: "h", token: "t", username: "u" },
      },
    });
    const accounts = listEnabledPulseBoardAccounts(cfg);
    const disabledFound = accounts.some((a) => a.accountId === "disabled");
    expect(disabledFound).toBe(false);
  });
});

