      delete process.env[key];
    }
  });

  afterEach(() => {
    for (const key of envKeys) {
      if (originalEnv[key] === undefined) {
        delete process.env[key];
      } else {
        process.env[key] = originalEnv[key];
      }
    }
  });

  it("returns configured=false when any required field is missing", () => {
    const cfg = makeConfig({ host: "https://pb.example.com", token: "tok" });
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(false);
  });

  it("returns configured=true when host, token, and username are all present", () => {
    const cfg = makeConfig({
