import { PulseBoardAccountSchema, PulseBoardChannelConfigSchema, PulseBoardConfigSchema } from "./config-schema.js";

describe("PulseBoardConfigSchema", () => {
  it("accepts a minimal valid config", () => {
    const result = PulseBoardConfigSchema.safeParse({
      host: "https://pb.example.com",
      token: "abc",
      username: "bot",
    });
    expect(result.success).toBe(true);
  });

  it("accepts config with boards array", () => {
    const result = PulseBoardConfigSchema.safeParse({
      host: "https://pb.example.com",
      token: "abc",
      username: "bot",
      boards: ["$general", "$ops"],
    });
    expect(result.success).toBe(true);
  });

  it("accepts allowFrom with mixed string and number entries", () => {
    const result = PulseBoardConfigSchema.safeParse({
      allowFrom: ["alice", 123, "bob"],
    });
    expect(result.success).toBe(true);
  });

  it("accepts groupAllowFrom", () => {
    const result = PulseBoardConfigSchema.safeParse({
      groupAllowFrom: ["alice", "bob"],
    });
    expect(result.success).toBe(true);
  });

  it("accepts per-board allowFrom inside groups", () => {
    const result = PulseBoardConfigSchema.safeParse({
      groups: {
        "$general": {
          requireMention: true,
          allowFrom: ["alice", "bob"],
        },
      },
    });
    expect(result.success).toBe(true);
  });

  it('rejects dmPolicy="open" without allowFrom including "*"', () => {
    const result = PulseBoardConfigSchema.safeParse({
      dmPolicy: "open",
      allowFrom: ["alice"],
    });
    expect(result.success).toBe(false);
  });

  it('accepts dmPolicy="open" when allowFrom includes "*"', () => {
    const result = PulseBoardConfigSchema.safeParse({
      dmPolicy: "open",
      allowFrom: ["*"],
    });
    expect(result.success).toBe(true);
  });

  it("accepts multi-account config with named accounts", () => {
    const result = PulseBoardConfigSchema.safeParse({
      accounts: {
        work: {
          host: "https://work.example.com",
          token: "worktok",
          username: "workbot",
        },
        personal: {
          host: "https://pers.example.com",
          token: "perstok",
          username: "persbot",
        },
      },
      defaultAccount: "work",
    });
    expect(result.success).toBe(true);
  });

  it("rejects unknown extra fields (strict schema)", () => {
    const result = PulseBoardConfigSchema.safeParse({
      unknownField: "value",
    });
    expect(result.success).toBe(false);
  });

  it("accepts textChunkLimit as a positive integer", () => {
    const result = PulseBoardConfigSchema.safeParse({
      textChunkLimit: 4000,
    });
    expect(result.success).toBe(true);
  });

  it("rejects textChunkLimit below 1", () => {
    const result = PulseBoardConfigSchema.safeParse({
      textChunkLimit: 0,
    });
    expect(result.success).toBe(false);
  });
});

describe("PulseBoardAccountSchema (nested account)", () => {
  it('rejects dmPolicy="open" without wildcard at account level', () => {
    const result = PulseBoardAccountSchema.safeParse({
      dmPolicy: "open",
      allowFrom: ["bob"],
    });
    expect(result.success).toBe(false);
  });
});

describe("PulseBoardChannelConfigSchema", () => {
  it("wraps the config schema and returns a buildChannelConfigSchema result", () => {
    expect(PulseBoardChannelConfigSchema).toBeDefined();
    expect(typeof PulseBoardChannelConfigSchema.parse).toBe("function");
  });
});

