import { describe, expect, it } from "vitest";
import {
  isBoardTarget,
  looksLikePulseBoardTargetId,
  normalizeBoardEntry,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardAllowlist,
  normalizePulseBoardMessagingTarget,
  resolvePulseBoardAllowlistMatch,
} from "./normalize.js";
import type { PulseBoardInboundMessage } from "./types.js";

function makeMessage(senderUsername: string): PulseBoardInboundMessage {
  return {
    messageId: "msg-1",
    target: "alice",
    senderUsername,
    text: "hello",
    timestamp: Date.now(),
    isGroup: false,
  };
}

describe("isBoardTarget", () => {
  it("returns true for $-prefixed targets", () => {
    expect(isBoardTarget("$general")).toBe(true);
    expect(isBoardTarget("$ops")).toBe(true);
  });

  it("returns false for plain usernames", () => {
    expect(isBoardTarget("alice")).toBe(false);
    expect(isBoardTarget("bob")).toBe(false);
  });

  it("returns false for empty string", () => {
    expect(isBoardTarget("")).toBe(false);
  });
});

describe("looksLikePulseBoardTargetId", () => {
  it("returns true for valid board names", () => {
    expect(looksLikePulseBoardTargetId("$general")).toBe(true);
  });

  it("returns true for valid usernames", () => {
    expect(looksLikePulseBoardTargetId("alice123")).toBe(true);
  });

  it("returns false for empty string", () => {
    expect(looksLikePulseBoardTargetId("")).toBe(false);
  });

  it("returns false for whitespace-only string", () => {
    expect(looksLikePulseBoardTargetId("  ")).toBe(false);
  });

  it("returns false for strings containing spaces", () => {
    expect(looksLikePulseBoardTargetId("hello world")).toBe(false);
  });
});

describe("normalizePulseBoardMessagingTarget", () => {
  it("passes through a valid board target unchanged", () => {
    expect(normalizePulseBoardMessagingTarget("$general")).toBe("$general");
  });

  it("passes through a valid username unchanged", () => {
    expect(normalizePulseBoardMessagingTarget("alice")).toBe("alice");
  });

  it('strips "board:" prefix and adds $ prefix', () => {
    expect(normalizePulseBoardMessagingTarget("board:general")).toBe("$general");
  });

  it('strips "board:" prefix when $ already present', () => {
    expect(normalizePulseBoardMessagingTarget("board:$ops")).toBe("$ops");
  });

  it('strips "user:" prefix for DMs', () => {
    expect(normalizePulseBoardMessagingTarget("user:alice")).toBe("alice");
  });

  it('strips "pulseboard:" prefix', () => {
    expect(normalizePulseBoardMessagingTarget("pulseboard:$general")).toBe("$general");
  });

  it('strips nested "pulseboard:user:" prefix', () => {
    expect(normalizePulseBoardMessagingTarget("pulseboard:user:alice")).toBe("alice");
  });

  it("returns undefined for empty string", () => {
    expect(normalizePulseBoardMessagingTarget("")).toBeUndefined();
  });

  it("returns undefined for whitespace-only string", () => {
    expect(normalizePulseBoardMessagingTarget("  ")).toBeUndefined();
  });

  it("strips leading/trailing whitespace before processing", () => {
    expect(normalizePulseBoardMessagingTarget("  $ops  ")).toBe("$ops");
  });
});

describe("normalizePulseBoardAllowEntry", () => {
  it("lowercases usernames", () => {
    expect(normalizePulseBoardAllowEntry("Alice")).toBe("alice");
  });

  it("strips pulseboard: prefix", () => {
    expect(normalizePulseBoardAllowEntry("pulseboard:alice")).toBe("alice");
  });

  it("strips user: prefix", () => {
    expect(normalizePulseBoardAllowEntry("user:alice")).toBe("alice");
  });

  it("preserves wildcard", () => {
    expect(normalizePulseBoardAllowEntry("*")).toBe("*");
  });

  it("returns empty string for whitespace input", () => {
    expect(normalizePulseBoardAllowEntry("  ")).toBe("");
  });
});

describe("normalizePulseBoardAllowlist", () => {
  it("maps and filters entries", () => {
    expect(normalizePulseBoardAllowlist(["Alice", "BOB", ""])).toEqual(["alice", "bob"]);
  });

  it("returns empty array for undefined input", () => {
    expect(normalizePulseBoardAllowlist(undefined)).toEqual([]);
  });

  it("handles numeric entries by stringifying", () => {
    expect(normalizePulseBoardAllowlist([123])).toEqual(["123"]);
  });
});

describe("resolvePulseBoardAllowlistMatch", () => {
  it("allows when * wildcard is present", () => {
    expect(
      resolvePulseBoardAllowlistMatch({
        allowFrom: ["*"],
        message: makeMessage("anyone"),
      }).allowed,
    ).toBe(true);
  });

  it("allows when sender username matches", () => {
    expect(
      resolvePulseBoardAllowlistMatch({
        allowFrom: ["alice"],
        message: makeMessage("alice"),
      }).allowed,
    ).toBe(true);
  });

  it("allows case-insensitive match", () => {
    expect(
      resolvePulseBoardAllowlistMatch({
        allowFrom: ["alice"],
        message: makeMessage("ALICE"),
      }).allowed,
    ).toBe(true);
  });

  it("denies when sender not in list", () => {
    expect(
      resolvePulseBoardAllowlistMatch({
        allowFrom: ["alice"],
        message: makeMessage("bob"),
      }).allowed,
    ).toBe(false);
  });

  it("denies for empty allowlist", () => {
    expect(
      resolvePulseBoardAllowlistMatch({
        allowFrom: [],
        message: makeMessage("alice"),
      }).allowed,
    ).toBe(false);
  });
});

describe("normalizeBoardEntry", () => {
  it("adds $ prefix to bare board names", () => {
    expect(normalizeBoardEntry("general")).toBe("$general");
  });

  it("passes through already-prefixed board names", () => {
    expect(normalizeBoardEntry("$ops")).toBe("$ops");
  });

  it("preserves wildcard", () => {
    expect(normalizeBoardEntry("*")).toBe("*");
  });

  it("returns null for empty string", () => {
    expect(normalizeBoardEntry("")).toBeNull();
  });
});

