import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
import type { CoreConfig } from "./types.js";

// Mock the runtime store so sendMessagePulseBoard can work without a real runtime.
vi.mock("../runtime-api.js", async (importOriginal) => {
  const original = await importOriginal<typeof import("../runtime-api.js")>();
  return {
    ...original,
    // chunkTextForOutbound and deliverFormattedTextWithAttachments are local to runtime-api,
    // so no need to mock them. We only need DEFAULT_ACCOUNT_ID and PAIRING_APPROVED_MESSAGE.
  };
});

vi.mock("./runtime.js", () => ({
  getPulseBoardRuntime: vi.fn(() => ({
    config: {
      loadConfig: () =>
        ({
          channels: {
            pulseboard: {
              host: "https://pb.example.com",
              token: "runtime-tok",
              username: "runtimebot",
            },
          },
        }) as CoreConfig,
    },
    channel: {
      activity: {
        record: vi.fn(),
      },
    },
