import { describe, expect, it } from "vitest";

// Import pulseBoardPlugin statically; the runtime is never initialized in this
// test so we only validate the plugin's structural properties.
vi.mock("./runtime.js", () => ({
  getPulseBoardRuntime: () => {
    throw new Error("PulseBoard runtime not initialized");
  },
  setPulseBoardRuntime: () => {},
  clearPulseBoardRuntime: () => {},
}));

// Lightweight mock for all openclaw SDK paths used at module load time.
vi.mock("openclaw/plugin-sdk/core", async (importOriginal) => {
  // Use the real implementation where possible; mock only what prevents load.
  try {
    return await importOriginal();
  } catch {
    return {
      createChatChannelPlugin: (opts: unknown) => opts,
      defineChannelPluginEntry: (opts: unknown) => opts,
      getChatChannelMeta: (id: string) => ({ id, label: id, selectionLabel: id, blurb: "", docsPath: `/${id}` }),
      describeAccountSnapshot: (opts: unknown) => opts,
    };
  }
});

import { pulseBoardPlugin } from "./channel.js";

describe("pulseBoardPlugin structure", () => {
  it("has the correct channel id", () => {
    expect(pulseBoardPlugin.id ?? (pulseBoardPlugin as unknown as { base?: { id?: string } }).base?.id).toBe("pulseboard");
  });

  it("declares both direct and group chat types", () => {
    const capabilities =
      (pulseBoardPlugin as unknown as { capabilities?: { chatTypes?: string[] } }).capabilities ??
      (pulseBoardPlugin as unknown as { base?: { capabilities?: { chatTypes?: string[] } } }).base
        ?.capabilities;
    expect(capabilities?.chatTypes).toContain("direct");
    expect(capabilities?.chatTypes).toContain("group");
  });

  it("has a 4000-character text chunk limit", () => {
    // The textChunkLimit may be nested under outbound.base or outbound directly.
    const outbound = (pulseBoardPlugin as unknown as {
      outbound?: { base?: { textChunkLimit?: number }; textChunkLimit?: number };
    }).outbound;
    const limit = outbound?.base?.textChunkLimit ?? outbound?.textChunkLimit;
    expect(limit).toBe(4000);
  });

  it("uses direct delivery mode", () => {
    const outbound = (pulseBoardPlugin as unknown as {
      outbound?: { base?: { deliveryMode?: string }; deliveryMode?: string };
    }).outbound;
    const mode = outbound?.base?.deliveryMode ?? outbound?.deliveryMode;
    expect(mode).toBe("direct");
  });

  it("chunker function splits text correctly at the 4000-char limit", () => {
    const outbound = (pulseBoardPlugin as unknown as {
      outbound?: { base?: { chunker?: (text: string, limit: number) => string[] } };
    }).outbound;
    const chunker = outbound?.base?.chunker;
    if (!chunker) {
      // Plugin may expose chunker via chunkTextForOutbound in runtime-api
      return;
    }
    const long = "a".repeat(8100);
    const chunks = chunker(long, 4000);
    expect(chunks.length).toBe(3);
    for (const chunk of chunks) {
      expect(chunk.length).toBeLessThanOrEqual(4000);
    }
  });
});

