import { describe, expect, it } from "vitest";
import type { CoreConfig } from "./types.js";

function makeConfig(pulseboard: Record<string, unknown> = {}): CoreConfig {
  return { channels: { pulseboard } } as CoreConfig;
}

vi.mock("openclaw/plugin-sdk/account-id", async (importOriginal) => {
  try {
    return await importOriginal();
  } catch {
    return {
      DEFAULT_ACCOUNT_ID: "default",
      normalizeAccountId: (id: unknown) => (id ? String(id) : "default"),
    };
  }
});

vi.mock("openclaw/plugin-sdk/routing", async (importOriginal) => {
  try {
    return await importOriginal();
  } catch {
    return {
      normalizeAccountId: (id: unknown) => (id ? String(id) : "default"),
      DEFAULT_ACCOUNT_ID: "default",
    };
  }
});

vi.mock("openclaw/plugin-sdk/setup", async (importOriginal) => {
  try {
    return await importOriginal();
  } catch {
    return {
      patchScopedAccountConfig: ({
        cfg,
        channelKey,
        accountId,
        patch,
      }: {
        cfg: CoreConfig;
        channelKey: string;
        accountId: string;
        patch: Record<string, unknown>;
      }) => {
        const channels = (cfg as unknown as Record<string, unknown>).channels as Record<
          string,
          unknown
        >;
        return {
          ...cfg,
          channels: {
            ...channels,
            [channelKey]: {
              ...(channels?.[channelKey] as Record<string, unknown>),
              ...patch,
            },
          },
        };
      },
      applyAccountNameToChannelSection: ({ cfg }: { cfg: CoreConfig }) => cfg,
      createTopLevelChannelAllowFromSetter:
        ({ channel }: { channel: string }) =>
        (cfg: CoreConfig, allowFrom: string[]) =>
          ({ ...cfg, channels: { ...cfg.channels, [channel]: { ...cfg.channels?.[channel as keyof typeof cfg.channels], allowFrom } } }),
      createTopLevelChannelDmPolicySetter:
        ({ channel }: { channel: string }) =>
        (cfg: CoreConfig, dmPolicy: string) =>
          ({ ...cfg, channels: { ...cfg.channels, [channel]: { ...cfg.channels?.[channel as keyof typeof cfg.channels], dmPolicy } } }),
      createSetupInputPresenceValidator:
        ({ whenNotUseEnv }: { whenNotUseEnv: Array<{ someOf: string[]; message: string }> }) =>
        ({ input }: { input: Record<string, unknown> }) => {
          for (const rule of whenNotUseEnv) {
            const hasAny = rule.someOf.some((key) => String(input[key] ?? "").trim());
            if (!hasAny) {
              return rule.message;
            }
          }
          return null;
        },
      createAllowFromSection: () => ({}),
      createStandardChannelSetupStatus: () => ({}),
      formatDocsLink: (path: string) => `https://docs.openclaw.ai${path}`,
      setSetupChannelEnabled: (cfg: CoreConfig) => cfg,
    };
  }
});

describe("pulseBoardSetupAdapter", () => {
  it("validateInput returns error when host is missing", async () => {
    const { pulseBoardSetupAdapter } = await import("./setup-core.js");
    const result = pulseBoardSetupAdapter.validateInput?.({
      cfg: makeConfig(),
      accountId: "default",
      input: { token: "tok", username: "bot" },
    });
    expect(result).toBeTruthy();
    expect(String(result)).toContain("host");
  });

  it("validateInput returns error when token is missing", async () => {
    const { pulseBoardSetupAdapter } = await import("./setup-core.js");
    const result = pulseBoardSetupAdapter.validateInput?.({
      cfg: makeConfig(),
      accountId: "default",
      input: { host: "https://pb.example.com", username: "bot" },
    });
    expect(result).toBeTruthy();
    expect(String(result)).toContain("token");
  });

  it("validateInput returns error when username is missing", async () => {
    const { pulseBoardSetupAdapter } = await import("./setup-core.js");
    const result = pulseBoardSetupAdapter.validateInput?.({
      cfg: makeConfig(),
      accountId: "default",
      input: { host: "https://pb.example.com", token: "tok" },
    });
    expect(result).toBeTruthy();
    expect(String(result)).toContain("username");
  });

  it("validateInput returns null when all required fields are present", async () => {
    const { pulseBoardSetupAdapter } = await import("./setup-core.js");
    const result = pulseBoardSetupAdapter.validateInput?.({
      cfg: makeConfig(),
      accountId: "default",
      input: { host: "https://pb.example.com", token: "tok", username: "bot" },
    });
    expect(result).toBeNull();
  });

  it("applyAccountConfig writes host, token, username, and boards", async () => {
    const { pulseBoardSetupAdapter } = await import("./setup-core.js");
    const cfg = makeConfig();
    const result = pulseBoardSetupAdapter.applyAccountConfig({
      cfg,
      accountId: "default",
      input: {
        host: "https://pb.example.com",
        token: "mytoken",
        username: "mybot",
        boards: ["$general"],
      },
    });
    const pb = (result as CoreConfig).channels?.pulseboard;
    expect(pb?.host).toBe("https://pb.example.com");
    expect(pb?.token).toBe("mytoken");
    expect(pb?.username).toBe("mybot");
    expect(pb?.boards).toEqual(["$general"]);
  });
});

describe("setPulseBoardDmPolicy", () => {
  it("sets the dmPolicy on the top-level pulseboard config", async () => {
    const { setPulseBoardDmPolicy } = await import("./setup-core.js");
    const cfg = makeConfig({ dmPolicy: "pairing" });
    const updated = setPulseBoardDmPolicy(cfg, "disabled");
    expect((updated as CoreConfig).channels?.pulseboard?.dmPolicy).toBe("disabled");
  });
});

describe("setPulseBoardAllowFrom", () => {
  it("sets allowFrom on the top-level pulseboard config", async () => {
    const { setPulseBoardAllowFrom } = await import("./setup-core.js");
    const cfg = makeConfig();
    const updated = setPulseBoardAllowFrom(cfg, ["alice", "bob"]);
    expect((updated as CoreConfig).channels?.pulseboard?.allowFrom).toEqual(["alice", "bob"]);
  });
});

