  it("validateInput returns error when token is missing", async () => {
    const { pulseBoardSetupAdapter } = await import("./setup-core.js");
    const result = pulseBoardSetupAdapter.validateInput?.({
      cfg: makeConfig(),
      accountId: "default",
      input: { host: "https://pb.example.com", username: "bot" },
    });
    expect(result).toBeTruthy();
    expect(String(result)).toContain("token");
  });

  it("validateInput returns error when username is missing", async () => {
    const { pulseBoardSetupAdapter } = await import("./setup-core.js");
    const result = pulseBoardSetupAdapter.validateInput?.({
      cfg: makeConfig(),
      accountId: "default",
      input: { host: "https://pb.example.com", token: "tok" },
    });
    expect(result).toBeTruthy();
    expect(String(result)).toContain("username");
  });

  it("validateInput returns null when all required fields are present", async () => {
    const { pulseBoardSetupAdapter } = await import("./setup-core.js");
    const result = pulseBoardSetupAdapter.validateInput?.({
      cfg: makeConfig(),
      accountId: "default",
      input: { host: "https://pb.example.com", token: "tok", username: "bot" },
    });
    expect(result).toBeNull();
  });

  it("applyAccountConfig writes host, token, username, and boards", async () => {
    const { pulseBoardSetupAdapter } = await import("./setup-core.js");
    const cfg = makeConfig();
    const result = pulseBoardSetupAdapter.applyAccountConfig({
      cfg,
      accountId: "default",
      input: {
        host: "https://pb.example.com",
        token: "mytoken",
        username: "mybot",
        boards: ["$general"],
      },
    });
    const pb = (result as CoreConfig).channels?.pulseboard;
    expect(pb?.host).toBe("https://pb.example.com");
    expect(pb?.token).toBe("mytoken");
    expect(pb?.username).toBe("mybot");
    expect(pb?.boards).toEqual(["$general"]);
  });
});

describe("setPulseBoardDmPolicy", () => {
  it("sets the dmPolicy on the top-level pulseboard config", async () => {
    const { setPulseBoardDmPolicy } = await import("./setup-core.js");
    const cfg = makeConfig({ dmPolicy: "pairing" });
    const updated = setPulseBoardDmPolicy(cfg, "disabled");
    expect((updated as CoreConfig).channels?.pulseboard?.dmPolicy).toBe("disabled");
  });
});

describe("setPulseBoardAllowFrom", () => {
  it("sets allowFrom on the top-level pulseboard config", async () => {
    const { setPulseBoardAllowFrom } = await import("./setup-core.js");
    const cfg = makeConfig();
    const updated = setPulseBoardAllowFrom(cfg, ["alice", "bob"]);
    expect((updated as CoreConfig).channels?.pulseboard?.allowFrom).toEqual(["alice", "bob"]);
  });
});

