import type { PluginRuntime } from "../runtime-api.js";

// Re-export PluginRuntime for use across the plugin.
export type { PluginRuntime };

// OpenClawConfig is the full config type; we narrow it to include pulseboard.
export type { OpenClawConfig } from "openclaw/plugin-sdk/core";

// RuntimeEnv: logger interface used in inbound and monitor.
export type RuntimeEnv = {
  log?: (message: string) => void;
  error?: (message: string) => void;
  warn?: (message: string) => void;
};

// Common config types (not available via a public SDK subpath; defined locally
// to match the runtime values used by channel-config-schema Zod definitions).
export type DmPolicy = "pairing" | "open" | "disabled";
export type GroupPolicy = "allowlist" | "open" | "disabled";

export type MarkdownConfig = {
  tables?: "off" | "text" | "gfm";
};

export type DmConfig = {
  historyLimit?: number;
  textChunkLimit?: number;
  requireMention?: boolean;
  systemPrompt?: string;
};

export type GroupToolPolicyConfig = "enabled" | "disabled" | "restricted";
export type GroupToolPolicyBySenderConfig = Record<string, GroupToolPolicyConfig>;

export type BlockStreamingCoalesceConfig = {
  maxDelayMs?: number;
  maxChunks?: number;
};

// BaseProbeResult: generic probe result type.
export type BaseProbeResult<ErrorDetails = string> = {
  ok: boolean;
  error?: ErrorDetails;
};

// PulseBoardBoardConfig: per-board overrides (mirrors IrcChannelConfig).
export type PulseBoardBoardConfig = {
  requireMention?: boolean;
  tools?: GroupToolPolicyConfig;
  toolsBySender?: GroupToolPolicyBySenderConfig;
  skills?: string[];
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

// PulseBoardAccountConfig: per-account settings.
export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  /** PulseBoard server URL, e.g. https://pb.example.com */
  host?: string;
  /** API bearer token (also from PULSEBOARD_TOKEN env) */
  token?: string;
  /** Bot username on the platform (also from PULSEBOARD_USERNAME env) */
  username?: string;
  /** Boards to subscribe to on startup, e.g. ["$general"] */
  boards?: string[];
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  defaultTo?: string;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  groups?: Record<string, PulseBoardBoardConfig>;
  markdown?: MarkdownConfig;
  textChunkLimit?: number;
  blockStreaming?: boolean;
  blockStreamingCoalesce?: BlockStreamingCoalesceConfig;
  responsePrefix?: string;
  dms?: Record<string, DmConfig>;
  historyLimit?: number;
  dmHistoryLimit?: number;
};

// PulseBoardConfig: top-level config (single-account + multi-account).
export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

// CoreConfig: OpenClawConfig narrowed to include pulseboard channel config.
import type { OpenClawConfig } from "openclaw/plugin-sdk/core";
export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

// PulseBoardInboundMessage: a normalized inbound event from a board or DM.
export type PulseBoardInboundMessage = {
  messageId: string;
  /** $board-name for group messages; sender username for DMs */
  target: string;
  senderUsername: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};

// PulseBoardProbe: result of a connectivity/health check.
export type PulseBoardProbe = BaseProbeResult<string> & {
  host: string;
  username: string;
  latencyMs?: number;
};

