21	type ReplyDispatchFromConfigOptions = Omit<GetReplyOptions, "onToolResult" | "onBlockReply">;
22	
23	/** Run `dispatchReplyFromConfig` with a dispatcher that always gets its settled callback. */
24	export async function dispatchReplyFromConfigWithSettledDispatcher(params: {
25	  cfg: OpenClawConfig;
26	  ctxPayload: FinalizedMsgContext;
27	  dispatcher: ReplyDispatcher;
28	  onSettled: () => void | Promise<void>;
29	  replyOptions?: ReplyDispatchFromConfigOptions;
30	  configOverride?: OpenClawConfig;
31	}): Promise<DispatchFromConfigResult> {
32	  return await withReplyDispatcher({
33	    dispatcher: params.dispatcher,
34	    onSettled: params.onSettled,
35	    run: () =>
36	      dispatchReplyFromConfig({
37	        ctx: params.ctxPayload,
38	        cfg: params.cfg,
39	        dispatcher: params.dispatcher,
40	        replyOptions: params.replyOptions,
41	        configOverride: params.configOverride,
42	      }),
43	  });
44	}
45	
46	/** Assemble the common inbound reply dispatch dependencies for a resolved route. */
47	export function buildInboundReplyDispatchBase(params: {
48	  cfg: OpenClawConfig;
49	  channel: string;
50	  accountId?: string;
51	  route: {
52	    agentId: string;
53	    sessionKey: string;
54	  };
55	  storePath: string;
56	  ctxPayload: FinalizedMsgContext;
57	  core: {
58	    channel: {
59	      session: {
60	        recordInboundSession: RecordInboundSessionFn;
61	      };
62	      reply: {
63	        dispatchReplyWithBufferedBlockDispatcher: DispatchReplyWithBufferedBlockDispatcherFn;
64	      };
65	    };
66	  };
67	}) {
68	  return {
69	    cfg: params.cfg,
70	    channel: params.channel,
71	    accountId: params.accountId,
72	    agentId: params.route.agentId,
73	    routeSessionKey: params.route.sessionKey,
74	    storePath: params.storePath,
75	    ctxPayload: params.ctxPayload,
76	    recordInboundSession: params.core.channel.session.recordInboundSession,
77	    dispatchReplyWithBufferedBlockDispatcher:
78	      params.core.channel.reply.dispatchReplyWithBufferedBlockDispatcher,
79	  };
80	}
81	
82	type BuildInboundReplyDispatchBaseParams = Parameters<typeof buildInboundReplyDispatchBase>[0];
83	type RecordInboundSessionAndDispatchReplyParams = Parameters<
84	  typeof recordInboundSessionAndDispatchReply
85	>[0];
