1	import type { ResolvedPulseBoardAccount } from "./accounts.js";
2	import {
3	  formatPulseBoardSenderId,
4	  normalizePulseBoardAllowlist,
5	  resolvePulseBoardAllowlistMatch,
6	} from "./normalize.js";
7	import {
8	  GROUP_POLICY_BLOCKED_LABEL,
9	  PAIRING_APPROVED_MESSAGE,
