81	/**
82	 * Handle an inbound PulseBoard message.
83	 *
84	 * Applies security gating (DM policy, group policy, allowlists, mention gate)
85	 * then routes the message to the appropriate agent session and delivers
86	 * the reply back to the sender/board.
87	 */
88	export async function handlePulseBoardInbound(params: {
89	  message: PulseBoardInboundMessage;
90	  account: ResolvedPulseBoardAccount;
91	  config: CoreConfig;
92	  runtime: RuntimeEnv;
93	  sendReply?: (target: string, text: string, replyToId?: string) => Promise<void>;
94	  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
95	}): Promise<void> {
96	  const { message, account, config, runtime, statusSink } = params;
97	  const core = getPulseBoardRuntime();
98	
99	  const rawBody = message.text?.trim() ?? "";
100	  if (!rawBody) {
101	    return;
102	  }
103	
104	  statusSink?.({ lastInboundAt: message.timestamp });
105	
106	  const senderDisplay = formatPulseBoardSenderId(message);
107	
108	  // -- Pairing controller --
109	  const pairing = createChannelPairingController({
110	    core,
111	    channel: CHANNEL_ID,
112	    accountId: account.accountId,
113	  });
114	
115	  // -- Group policy resolution --
116	  const dmPolicy = account.config.dmPolicy ?? "pairing";
117	  const defaultGroupPolicy = resolveDefaultGroupPolicy(config);
118	  const { groupPolicy, providerMissingFallbackApplied } = resolveAllowlistProviderRuntimeGroupPolicy(
119	    {
120	      providerConfigPresent: config.channels?.pulseboard !== undefined,
121	      groupPolicy: account.config.groupPolicy,
122	      defaultGroupPolicy,
123	    },
124	  );
125	  warnMissingProviderGroupPolicyFallbackOnce({
126	    providerMissingFallbackApplied,
127	    providerKey: "pulseboard",
128	    accountId: account.accountId,
129	    blockedLabel: GROUP_POLICY_BLOCKED_LABEL.channel,
130	    log: (msg) => runtime.log?.(msg),
131	  });
132	
133	  // -- Allowlists --
134	  const configAllowFrom = normalizePulseBoardAllowlist(account.config.allowFrom);
135	  const configGroupAllowFrom = normalizePulseBoardAllowlist(account.config.groupAllowFrom);
136	  const storeAllowFrom = await readStoreAllowFromForDmPolicy({
137	    provider: CHANNEL_ID,
138	    accountId: account.accountId,
139	    dmPolicy,
140	    readStore: pairing.readStoreForDmPolicy,
141	  });
142	  const storeAllowList = normalizePulseBoardAllowlist(storeAllowFrom);
143	
144	  const { effectiveAllowFrom, effectiveGroupAllowFrom } = resolveEffectiveAllowFromLists({
145	    allowFrom: configAllowFrom,
146	    groupAllowFrom: configGroupAllowFrom,
147	    storeAllowFrom: storeAllowList,
148	    dmPolicy,
149	    groupAllowFromFallbackToAllowFrom: false,
150	  });
151	
152	  // -- Board/group config lookup --
153	  const boardMatch = resolvePulseBoardGroupMatch({
154	    groups: account.config.groups,
155	    target: message.target,
156	  });
157	
158	  // -- Group access gate --
159	  if (message.isGroup) {
160	    if (groupPolicy === "disabled") {
161	      runtime.log?.(
162	        `pulseboard: drop board ${message.target} (${GROUP_POLICY_BLOCKED_LABEL.channel})`,
163	      );
164	      return;
165	    }
166	    if (groupPolicy === "allowlist") {
167	      const boardInAllowlist =
168	        boardMatch.boardConfig !== undefined || boardMatch.wildcardConfig !== undefined;
169	      if (!boardInAllowlist) {
170	        runtime.log?.(`pulseboard: drop board ${message.target} (not in allowlist)`);
171	        return;
172	      }
173	    }
174	  }
175	
176	  // Per-board allowFrom overrides.
177	  const directBoardAllowFrom = normalizePulseBoardAllowlist(boardMatch.boardConfig?.allowFrom);
178	  const wildcardBoardAllowFrom = normalizePulseBoardAllowlist(boardMatch.wildcardConfig?.allowFrom);
179	  const boardAllowFrom =
180	    directBoardAllowFrom.length > 0 ? directBoardAllowFrom : wildcardBoardAllowFrom;
181	
182	  // -- Sender gate --
183	  if (message.isGroup) {
184	    const outerAllowFrom = effectiveGroupAllowFrom;
185	    const innerAllowFrom = boardAllowFrom;
186	    const effectiveList = innerAllowFrom.length > 0 ? innerAllowFrom : outerAllowFrom;
187	    if (effectiveList.length > 0) {
188	      const senderAllowed = resolvePulseBoardAllowlistMatch({
189	        allowFrom: effectiveList,
190	        message,
191	      }).allowed;
192	      if (!senderAllowed) {
193	        logInboundDrop({ log: (line) => runtime.log?.(line), channel: CHANNEL_ID, reason: `policy=${groupPolicy}`, target: senderDisplay });
194	        return;
195	      }
196	    }
197	  } else {
198	    // DM gating
199	    if (dmPolicy === "disabled") {
200	      runtime.log?.(
201	        `pulseboard: drop DM sender=${senderDisplay} (dmPolicy=disabled)`,
202	      );
203	      return;
204	    }
205	    if (dmPolicy !== "open") {
206	      const dmAllowed = resolvePulseBoardAllowlistMatch({
207	        allowFrom: effectiveAllowFrom,
208	        message,
209	      }).allowed;
210	      if (!dmAllowed) {
211	        if (dmPolicy === "pairing") {
212	          await pairing.issueChallenge({
213	            senderId: senderDisplay.toLowerCase(),
214	            senderIdLine: `Your PulseBoard username: ${senderDisplay}`,
215	            meta: { name: message.senderUsername || undefined },
216	            sendPairingReply: async (text) => {
217	              await deliverPulseBoardReply({
218	                payload: { text },
219	                target: message.senderUsername,
220	                accountId: account.accountId,
221	                sendReply: params.sendReply,
222	                statusSink,
223	              });
224	            },
225	            onReplyError: (err) => {
226	              runtime.error?.(
227	                `pulseboard: pairing reply failed for ${senderDisplay}: ${String(err)}`,
228	              );
229	            },
230	          });
231	        }
232	        runtime.log?.(
233	          `pulseboard: drop DM sender ${senderDisplay} (dmPolicy=${dmPolicy})`,
234	        );
235	        return;
236	      }
237	    }
238	  }
239	
240	  // -- Mention gate (boards only) --
241	  const requireMention = message.isGroup
242	    ? resolveRequireMentionForBoard(boardMatch)
243	    : false;
244	
245	  if (message.isGroup && requireMention) {
246	    const mentionRegexes = core.channel.mentions.buildMentionRegexes(config);
247	    const botUsername = account.username;
248	    const explicitMentionRegex = botUsername
249	      ? new RegExp(`@?${botUsername.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "i")
250	      : null;
251	    const wasMentioned =
252	      core.channel.mentions.matchesMentionPatterns(rawBody, mentionRegexes) ||
253	      (explicitMentionRegex ? explicitMentionRegex.test(rawBody) : false);
254	
255	    if (!wasMentioned) {
256	      runtime.log?.(
257	        `pulseboard: skip board ${message.target} (no mention, requireMention=true)`,
258	      );
259	      return;
260	    }
261	  }
262	
263	  // -- Routing --
264	  const peerId = message.isGroup ? message.target : message.senderUsername;
265	  const chatType = message.isGroup ? "group" : "direct";
266	
267	  const route = core.channel.routing.resolveAgentRoute({
268	    cfg: config,
269	    channel: CHANNEL_ID,
270	    accountId: account.accountId,
271	    peer: {
272	      kind: chatType,
273	      id: peerId,
274	    },
275	  });
276	
277	  const fromLabel = message.isGroup ? message.target : senderDisplay;
278	  const storePath = core.channel.session.resolveStorePath(config.session?.store, {
279	    agentId: route.agentId,
280	  });
281	  const envelopeOptions = core.channel.reply.resolveEnvelopeFormatOptions(config);
282	  const previousTimestamp = core.channel.session.readSessionUpdatedAt({
283	    storePath,
284	    sessionKey: route.sessionKey,
285	  });
286	  const body = core.channel.reply.formatAgentEnvelope({
287	    channel: "PulseBoard",
288	    from: fromLabel,
289	    timestamp: message.timestamp,
290	    previousTimestamp,
291	    envelope: envelopeOptions,
292	    body: rawBody,
293	  });
294	
295	  const groupSystemPrompt = boardMatch.boardConfig?.systemPrompt?.trim() || undefined;
296	
297	  const ctxPayload = core.channel.reply.finalizeInboundContext({
298	    Body: body,
299	    RawBody: rawBody,
300	    CommandBody: rawBody,
301	    From: message.isGroup ? `pulseboard:board:${message.target}` : `pulseboard:${senderDisplay}`,
302	    To: `pulseboard:${peerId}`,
303	    SessionKey: route.sessionKey,
304	    AccountId: route.accountId,
305	    ChatType: chatType,
306	    ConversationLabel: fromLabel,
307	    SenderName: message.senderUsername || undefined,
308	    SenderId: senderDisplay,
309	    GroupSubject: message.isGroup ? message.target : undefined,
310	    GroupSystemPrompt: message.isGroup ? groupSystemPrompt : undefined,
311	    Provider: CHANNEL_ID,
312	    Surface: CHANNEL_ID,
313	    WasMentioned: message.isGroup ? true : undefined,
314	    MessageSid: message.messageId,
315	    Timestamp: message.timestamp,
316	    OriginatingChannel: CHANNEL_ID,
317	    OriginatingTo: `pulseboard:${peerId}`,
318	    CommandAuthorized: false,
319	  });
320	
321	  // -- Dispatch --
322	  // Use dispatchInboundDirectDmWithRuntime for DMs.
323	  // For group boards, use the PluginRuntime channel APIs directly.
324	  if (!message.isGroup) {
325	    const { dispatchInboundDirectDmWithRuntime } = await import(
326	      "openclaw/plugin-sdk/channel-inbound"
327	    );
328	    await dispatchInboundDirectDmWithRuntime({
329	      core,
330	      cfg: config,
331	      channel: CHANNEL_ID,
332	      accountId: account.accountId,
333	      route,
334	      storePath,
335	      ctxPayload,
336	      deliver: async (payload: OutboundReplyPayload) => {
337	        await deliverPulseBoardReply({
338	          payload,
339	          target: peerId,
340	          accountId: account.accountId,
341	          sendReply: params.sendReply,
342	          statusSink,
343	        });
344	      },
345	      onRecordError: (err: unknown) => {
346	        runtime.error?.(
347	          `pulseboard: failed updating session meta: ${String(err)}`,
348	        );
349	      },
350	      onDispatchError: (err: unknown) => {
351	        runtime.error?.(
352	          `pulseboard DM reply failed: ${String(err)}`,
353	        );
354	      },
355	    });
356	  } else {
357	    // Group boards: dispatch via the PluginRuntime inbound pipeline.
358	    await core.channel.inbound.dispatchWithRuntime({
359	      core,
360	      cfg: config,
361	      channel: CHANNEL_ID,
362	      accountId: account.accountId,
363	      route,
364	      storePath,
365	      ctxPayload,
366	      deliver: async (payload: OutboundReplyPayload) => {
367	        await deliverPulseBoardReply({
368	          payload,
