// Private runtime barrel for the bundled PulseBoard extension.
// Re-exports from public openclaw/plugin-sdk/* paths.
// There is no openclaw/plugin-sdk/pulseboard facade since PulseBoard is not a core channel.

export {
  logInboundDrop,
  dispatchInboundDirectDmWithRuntime,
  resolveMentionGating,
  resolveMentionGatingWithBypass,
} from "openclaw/plugin-sdk/channel-inbound";

export { createChannelPairingController } from "openclaw/plugin-sdk/channel-pairing";

export {
  GROUP_POLICY_BLOCKED_LABEL,
  resolveAllowlistProviderRuntimeGroupPolicy,
  resolveDefaultGroupPolicy,
  warnMissingProviderGroupPolicyFallbackOnce,
} from "openclaw/plugin-sdk/runtime-group-policy";

export {
  readStoreAllowFromForDmPolicy,
  resolveEffectiveAllowFromLists,
} from "openclaw/plugin-sdk/security-runtime";

export {
  buildBaseChannelStatusSummary,
  createComputedAccountStatusAdapter,
  createDefaultChannelRuntimeState,
} from "openclaw/plugin-sdk/status-helpers";

export { createAccountStatusSink } from "openclaw/plugin-sdk/channel-lifecycle";

export { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";

export type { PluginRuntime } from "openclaw/plugin-sdk/core";

// PAIRING_APPROVED_MESSAGE is not available via a public SDK subpath; define locally.
export const PAIRING_APPROVED_MESSAGE =
  "Pairing approved. You can now send messages to this agent.";

// chunkTextForOutbound is not available via a public SDK subpath.
// Implemented inline following the same pattern as the Matrix plugin's runtime-api.ts.
export function chunkTextForOutbound(text: string, limit: number): string[] {
  const chunks: string[] = [];
  let remaining = text;
  while (remaining.length > limit) {
    const window = remaining.slice(0, limit);
    const splitAt = Math.max(window.lastIndexOf("\n"), window.lastIndexOf(" "));
    const breakAt = splitAt > 0 ? splitAt : limit;
    chunks.push(remaining.slice(0, breakAt).trimEnd());
    remaining = remaining.slice(breakAt).trimStart();
  }
  if (remaining.length > 0 || text.length === 0) {
    chunks.push(remaining);
  }
  return chunks;
}

// deliverFormattedTextWithAttachments is not available via a public SDK subpath.
// Implemented as a minimal local helper used by inbound.ts.
export type OutboundReplyPayload = {
  text?: string;
  mediaUrls?: string[];
  mediaUrl?: string;
  replyToId?: string;
};

export async function deliverFormattedTextWithAttachments(params: {
  payload: OutboundReplyPayload;
  send: (opts: { text: string; replyToId?: string }) => Promise<void>;
}): Promise<boolean> {
  const text = params.payload.text?.trim() ?? "";
  const mediaUrl = params.payload.mediaUrls?.[0] ?? params.payload.mediaUrl;
  const combined = mediaUrl ? (text ? `${text}\n\n${mediaUrl}` : mediaUrl) : text;
  if (!combined) {
    return false;
  }
  await params.send({ text: combined, replyToId: params.payload.replyToId });
  return true;
}

