} from "../runtime-api.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { sendMessagePulseBoard } from "./send.js";
import type { CoreConfig, PulseBoardBoardConfig, PulseBoardInboundMessage } from "./types.js";

const CHANNEL_ID = "pulseboard" as const;

// Suppress the unused import warning — PAIRING_APPROVED_MESSAGE is used indirectly
// via pairingMessage below but TypeScript may not see it without the reference.
void PAIRING_APPROVED_MESSAGE;

type BoardMatch = {
  boardConfig?: PulseBoardBoardConfig;
  wildcardConfig?: PulseBoardBoardConfig;
};

function resolvePulseBoardGroupMatch(params: {
  groups?: Record<string, PulseBoardBoardConfig | undefined>;
  target: string;
}): BoardMatch {
  return {
    boardConfig: params.groups?.[params.target],
    wildcardConfig: params.groups?.["*"],
  };
}

function resolveRequireMentionForBoard(match: BoardMatch): boolean {
  if (match.boardConfig?.requireMention !== undefined) {
    return match.boardConfig.requireMention;
  }
  if (match.wildcardConfig?.requireMention !== undefined) {
    return match.wildcardConfig.requireMention;
  }
  // Default: boards require an @-mention.
  return true;
}

async function deliverPulseBoardReply(params: {
  payload: OutboundReplyPayload;
  target: string;
  accountId: string;
  sendReply?: (target: string, text: string, replyToId?: string) => Promise<void>;
  statusSink?: (patch: { lastOutboundAt?: number }) => void;
}): Promise<void> {
  await deliverFormattedTextWithAttachments({
    payload: params.payload,
    send: async ({ text, replyToId }) => {
      if (params.sendReply) {
        await params.sendReply(params.target, text, replyToId);
      } else {
        await sendMessagePulseBoard(params.target, text, {
          accountId: params.accountId,
          replyTo: replyToId,
        });
      }
      params.statusSink?.({ lastOutboundAt: Date.now() });
    },
  });
}

/**
 * Handle an inbound PulseBoard message.
 *
 * Applies security gating (DM policy, group policy, allowlists, mention gate)
 * then routes the message to the appropriate agent session and delivers
 * the reply back to the sender/board.
 */
export async function handlePulseBoardInbound(params: {
  message: PulseBoardInboundMessage;
  account: ResolvedPulseBoardAccount;
  config: CoreConfig;
  runtime: RuntimeEnv;
  sendReply?: (target: string, text: string, replyToId?: string) => Promise<void>;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
}): Promise<void> {
  const { message, account, config, runtime, statusSink } = params;
  const core = getPulseBoardRuntime();

  const rawBody = message.text?.trim() ?? "";
  if (!rawBody) {
    return;
  }

  statusSink?.({ lastInboundAt: message.timestamp });

  const senderDisplay = formatPulseBoardSenderId(message);

  // -- Pairing controller --
  const pairing = createChannelPairingController({
    core,
    channel: CHANNEL_ID,
    accountId: account.accountId,
  });

  // -- Group policy resolution --
  const dmPolicy = account.config.dmPolicy ?? "pairing";
  const defaultGroupPolicy = resolveDefaultGroupPolicy(config);
  const { groupPolicy, providerMissingFallbackApplied } = resolveAllowlistProviderRuntimeGroupPolicy(
    {
      providerConfigPresent: config.channels?.pulseboard !== undefined,
      groupPolicy: account.config.groupPolicy,
      defaultGroupPolicy,
    },
  );
  warnMissingProviderGroupPolicyFallbackOnce({
    providerMissingFallbackApplied,
    providerKey: "pulseboard",
    accountId: account.accountId,
    blockedLabel: GROUP_POLICY_BLOCKED_LABEL.channel,
    log: (msg) => runtime.log?.(msg),
  });

  // -- Allowlists --
  const configAllowFrom = normalizePulseBoardAllowlist(account.config.allowFrom);
  const configGroupAllowFrom = normalizePulseBoardAllowlist(account.config.groupAllowFrom);
  const storeAllowFrom = await readStoreAllowFromForDmPolicy({
    provider: CHANNEL_ID,
    accountId: account.accountId,
    dmPolicy,
    readStore: pairing.readStoreForDmPolicy,
  });
  const storeAllowList = normalizePulseBoardAllowlist(storeAllowFrom);

  const { effectiveAllowFrom, effectiveGroupAllowFrom } = resolveEffectiveAllowFromLists({
    allowFrom: configAllowFrom,
    groupAllowFrom: configGroupAllowFrom,
    storeAllowFrom: storeAllowList,
    dmPolicy,
    groupAllowFromFallbackToAllowFrom: false,
  });

  // -- Board/group config lookup --
  const boardMatch = resolvePulseBoardGroupMatch({
    groups: account.config.groups,
    target: message.target,
  });

  // -- Group access gate --
  if (message.isGroup) {
    if (groupPolicy === "disabled") {
      runtime.log?.(
        `pulseboard: drop board ${message.target} (${GROUP_POLICY_BLOCKED_LABEL.channel})`,
      );
      return;
    }
    if (groupPolicy === "allowlist") {
      const boardInAllowlist =
        boardMatch.boardConfig !== undefined || boardMatch.wildcardConfig !== undefined;
      if (!boardInAllowlist) {
        runtime.log?.(`pulseboard: drop board ${message.target} (not in allowlist)`);
        return;
      }
    }
  }

  // Per-board allowFrom overrides.
  const directBoardAllowFrom = normalizePulseBoardAllowlist(boardMatch.boardConfig?.allowFrom);
  const wildcardBoardAllowFrom = normalizePulseBoardAllowlist(boardMatch.wildcardConfig?.allowFrom);
  const boardAllowFrom =
    directBoardAllowFrom.length > 0 ? directBoardAllowFrom : wildcardBoardAllowFrom;

  // -- Sender gate --
  if (message.isGroup) {
    const outerAllowFrom = effectiveGroupAllowFrom;
    const innerAllowFrom = boardAllowFrom;
    const effectiveList = innerAllowFrom.length > 0 ? innerAllowFrom : outerAllowFrom;
    if (effectiveList.length > 0) {
      const senderAllowed = resolvePulseBoardAllowlistMatch({
        allowFrom: effectiveList,
        message,
      }).allowed;
      if (!senderAllowed) {
        logInboundDrop({ log: (line) => runtime.log?.(line), channel: CHANNEL_ID, reason: `policy=${groupPolicy}`, target: senderDisplay });
        return;
      }
    }
  } else {
    // DM gating
    if (dmPolicy === "disabled") {
      runtime.log?.(
        `pulseboard: drop DM sender=${senderDisplay} (dmPolicy=disabled)`,
      );
      return;
    }
    if (dmPolicy !== "open") {
      const dmAllowed = resolvePulseBoardAllowlistMatch({
        allowFrom: effectiveAllowFrom,
        message,
      }).allowed;
      if (!dmAllowed) {
        if (dmPolicy === "pairing") {
          await pairing.issueChallenge({
            senderId: senderDisplay.toLowerCase(),
            senderIdLine: `Your PulseBoard username: ${senderDisplay}`,
            meta: { name: message.senderUsername || undefined },
            sendPairingReply: async (text) => {
              await deliverPulseBoardReply({
                payload: { text },
                target: message.senderUsername,
                accountId: account.accountId,
                sendReply: params.sendReply,
                statusSink,
              });
            },
            onReplyError: (err) => {
              runtime.error?.(
                `pulseboard: pairing reply failed for ${senderDisplay}: ${String(err)}`,
              );
            },
          });
        }
        runtime.log?.(
          `pulseboard: drop DM sender ${senderDisplay} (dmPolicy=${dmPolicy})`,
        );
        return;
      }
    }
  }

  // -- Mention gate (boards only) --
  const requireMention = message.isGroup
    ? resolveRequireMentionForBoard(boardMatch)
    : false;

  if (message.isGroup && requireMention) {
    const mentionRegexes = core.channel.mentions.buildMentionRegexes(config);
    const botUsername = account.username;
    const explicitMentionRegex = botUsername
      ? new RegExp(`@?${botUsername.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "i")
      : null;
    const wasMentioned =
      core.channel.mentions.matchesMentionPatterns(rawBody, mentionRegexes) ||
      (explicitMentionRegex ? explicitMentionRegex.test(rawBody) : false);

    if (!wasMentioned) {
      runtime.log?.(
        `pulseboard: skip board ${message.target} (no mention, requireMention=true)`,
      );
      return;
    }
  }

  // -- Routing --
  const peerId = message.isGroup ? message.target : message.senderUsername;
  const chatType = message.isGroup ? "group" : "direct";

  const route = core.channel.routing.resolveAgentRoute({
    cfg: config,
    channel: CHANNEL_ID,
    accountId: account.accountId,
    peer: {
      kind: chatType,
      id: peerId,
    },
  });

  const fromLabel = message.isGroup ? message.target : senderDisplay;
  const storePath = core.channel.session.resolveStorePath(config.session?.store, {
    agentId: route.agentId,
  });
  const envelopeOptions = core.channel.reply.resolveEnvelopeFormatOptions(config);
  const previousTimestamp = core.channel.session.readSessionUpdatedAt({
    storePath,
    sessionKey: route.sessionKey,
  });
  const body = core.channel.reply.formatAgentEnvelope({
    channel: "PulseBoard",
    from: fromLabel,
    timestamp: message.timestamp,
    previousTimestamp,
    envelope: envelopeOptions,
    body: rawBody,
  });

  const groupSystemPrompt = boardMatch.boardConfig?.systemPrompt?.trim() || undefined;

  const ctxPayload = core.channel.reply.finalizeInboundContext({
    Body: body,
    RawBody: rawBody,
    CommandBody: rawBody,
    From: message.isGroup ? `pulseboard:board:${message.target}` : `pulseboard:${senderDisplay}`,
    To: `pulseboard:${peerId}`,
    SessionKey: route.sessionKey,
    AccountId: route.accountId,
    ChatType: chatType,
    ConversationLabel: fromLabel,
    SenderName: message.senderUsername || undefined,
    SenderId: senderDisplay,
    GroupSubject: message.isGroup ? message.target : undefined,
    GroupSystemPrompt: message.isGroup ? groupSystemPrompt : undefined,
    Provider: CHANNEL_ID,
    Surface: CHANNEL_ID,
    WasMentioned: message.isGroup ? true : undefined,
    MessageSid: message.messageId,
    Timestamp: message.timestamp,
    OriginatingChannel: CHANNEL_ID,
    OriginatingTo: `pulseboard:${peerId}`,
    CommandAuthorized: false,
  });

  // -- Dispatch --
  // Use dispatchInboundDirectDmWithRuntime for DMs.
  // For group boards, use the PluginRuntime channel APIs directly.
  if (!message.isGroup) {
    const { dispatchInboundDirectDmWithRuntime } = await import(
      "openclaw/plugin-sdk/channel-inbound"
    );
    await dispatchInboundDirectDmWithRuntime({
      core,
      cfg: config,
      channel: CHANNEL_ID,
      accountId: account.accountId,
      route,
      storePath,
      ctxPayload,
      deliver: async (payload: OutboundReplyPayload) => {
        await deliverPulseBoardReply({
          payload,
          target: peerId,
          accountId: account.accountId,
          sendReply: params.sendReply,
          statusSink,
        });
      },
      onRecordError: (err: unknown) => {
        runtime.error?.(
          `pulseboard: failed updating session meta: ${String(err)}`,
        );
      },
      onDispatchError: (err: unknown) => {
        runtime.error?.(
          `pulseboard DM reply failed: ${String(err)}`,
        );
      },
    });
  } else {
    // Group boards: dispatch via the PluginRuntime inbound pipeline.
    await core.channel.inbound.dispatchWithRuntime({
      core,
      cfg: config,
      channel: CHANNEL_ID,
      accountId: account.accountId,
      route,
      storePath,
      ctxPayload,
      deliver: async (payload: OutboundReplyPayload) => {
        await deliverPulseBoardReply({
          payload,
          target: peerId,
          accountId: account.accountId,
          sendReply: params.sendReply,
          statusSink,
        });
      },
      onRecordError: (err: unknown) => {
        runtime.error?.(
          `pulseboard: failed updating session meta: ${String(err)}`,
        );
      },
      onDispatchError: (err: unknown, info: { kind?: string }) => {
        runtime.error?.(
          `pulseboard ${info?.kind ?? "group"} reply failed: ${String(err)}`,
        );
      },
      replyOptions: {
        skillFilter: boardMatch.boardConfig?.skills,
      },
    });
  }
}

